VALUES
  ('dietitian-moex-00483', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '實驗課上某生分別配製了胃蛋白酶（pepsin）與胰蛋白酶（trypsin）酵素溶液，但忘記標示酵素名稱。下 列何者可最快速且經濟的方法，分辨此二酵素溶液？', '["取適量酵素溶液與白蛋白進行水解反應1小時後，測量胺基酸產物種類", "取適量酵素溶液與白蛋白在pH=2條件下進行水解反應後，利用雙脲試劑（Biuret reagent）進行呈色反應 和比較", "利用單株抗體的專一性進行抗體與酵素的免疫分析反應（ELISA）後，測量特定波長的吸光值", "取適量酵素溶液與白蛋白在37℃下進行水解反應後，利用比色法測量產物肽鏈（peptide）的呈色反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00484', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '參與粒線體電子傳遞鏈反應的NADH或FADH 來自於下列何者？①檸檬酸循環　②糖解作用　③脂肪酸β氧化 2 作用', '["僅①②", "僅①③", "僅②③", "①②③"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00485', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '酵素動力學最常用的公式是： ，關於K 與V 的單位說明，下列何者正確？ m max', '["K 與V 都是係數，故沒有單位 m max", "-1 K 與V 都是反應速率常數，單位都是sec m max", "K 是反應基質的含量，如莫耳數mmol m", "只有K 是濃度單位，如mol/L m"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00486', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於丙酮酸去氫酶激酶（pyruvate dehydrogenase kinase, PDK）在生化代謝調節的敘述，下列何者錯誤？', '["參與細胞呼吸作用，與癌症進展有關", "磷酸化且活化丙酮酸去氫酶（pyruvate dehydrogenase）", "可決定細胞葡萄糖氧化產能，亦或脂肪酸產能", "參與糖質新生的酵素"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "4b45a176e23e", "answer_pdf_sha1": "84b9ea3552b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00487', 'dietitian', 'dietitian-moex-113-2755cf97', 'sub-dietitian-05', NULL, 'essay', '請試述憩室症（diverticulosis）與憩室炎（diverticulitis）的病因及飲食原則之差異性。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:50+00:00", "source_pdf_sha1": "21691dff4ad8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113030", "c": "102", "s": "11", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "膳食療養學", "year": "113", "exam_name": "113年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": "1", "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
